// @ts-check
export default async function instantiate(
    /**
     * @type {BufferSource|Response|Promise<BufferSource|Response>} }
     */
    wasmSource
) {
    if (wasmSource instanceof Promise) {
        wasmSource = await wasmSource;
    }
    const js_code = {
        'kotlin.captureStackTrace': () => new Error().stack,
        'kotlin.wasm.internal.throwJsError': (message, wasmTypeName, stack) => {
            const error = new Error();
            error.message = message;
            error.name = wasmTypeName;
            error.stack = stack;
            throw error;
        },
        'kotlin.wasm.internal.stringLength': (x) => x.length,
        'kotlin.wasm.internal.jsExportStringToWasm': (
            src,
            srcOffset,
            srcLength,
            dstAddr
        ) => {
            const mem16 = new Uint16Array(
                wasmExports.memory.buffer,
                dstAddr,
                srcLength
            );
            let arrayIndex = 0;
            let srcIndex = srcOffset;
            while (arrayIndex < srcLength) {
                mem16.set([src.charCodeAt(srcIndex)], arrayIndex);
                srcIndex++;
                arrayIndex++;
            }
        },
        'kotlin.wasm.internal.importStringFromWasm': (
            address,
            length,
            prefix
        ) => {
            const mem16 = new Uint16Array(
                wasmExports.memory.buffer,
                address,
                length
            );
            const str = String.fromCharCode.apply(null, mem16);
            return prefix == null ? str : prefix + str;
        },
        'kotlin.wasm.internal.getJsEmptyString': () => '',
        'kotlin.wasm.internal.isNullish': (ref) => ref == null,
        'kotlin.wasm.internal.getJsTrue': () => true,
        'kotlin.wasm.internal.getJsFalse': () => false,
        'kotlin.random.initialSeed': () =>
            (Math.random() * Math.pow(2, 32)) | 0,
        'li.songe.matches.__convertKotlinClosureToJsClosure_((String)->Boolean)':
            (f) => (p0) =>
                wasmExports['__callFunction_((String)->Boolean)'](f, p0),
    };

    // Placed here to give access to it from externals (js_code)
    let wasmInstance;
    let require;
    let wasmExports;

    const wasmFilePath = './gkd-wasm_matches-wasm-js.wasm';
    const importObject = {
        js_code,
    };

    try {
        if (wasmSource instanceof Response) {
            wasmInstance = (
                await WebAssembly.instantiateStreaming(wasmSource, importObject)
            ).instance;
        } else {
            const wasmModule = new WebAssembly.Module(wasmSource);
            wasmInstance = new WebAssembly.Instance(wasmModule, importObject);
        }
    } catch (e) {
        if (e instanceof WebAssembly.CompileError) {
            let text = `Please make sure that your runtime environment supports the latest version of Wasm GC and Exception-Handling proposals.
For more information, see https://kotl.in/wasm-help
`;
            console.error(text);
        }
        throw e;
    }

    wasmExports = wasmInstance.exports;
    // @ts-ignore
    wasmExports._initialize();

    return { instance: wasmInstance, exports: wasmExports };
}
